(async function() {
  'use strict';
  const NS = 'blueprintWarden';
  function log(...args) { try { console.log('[BlueprintWarden]', ...args); } catch (_) {} }
  function getThread() { try { return globalThis?.oc?.thread || null; } catch (_) { return null; } }
  function getCharacter() { try { return globalThis?.oc?.character || null; } catch (_) { return null; } }
  function getThreadStore() {
     const thread = getThread();
     if (!thread) return null;
     thread.customData ||= {};
     const now = Date.now();
     if (!thread.customData[NS] || thread.customData[NS].version !== 2) {
        thread.customData[NS] = {
          version: 2,
          createdAt: now,
          updatedAt: now,
          conceptHistory: [],
          latestUserConcept: '',
          latestBotTypeGuess: '',
          latestModeGuess: '',
          latestSections: {},
          latestRaw: '',
          latestUnknownHandoffPrompt: '',
          flags: { hasSkeleton:false, readyForHandoff:false },
          versionHistory: [],
          summaryHistory: []
        };
     }
     return thread.customData[NS];
  }
  function cleanText(text) { return String(text || '').replace(/\r/g,'').replace(/\u200B/g,'').trim(); }
  function parseSections(text) { 
     const lines = cleanText(text).split('\n');
     const sections = {};
     let currentKey = null;
     let buffer = [];
     function flush() { if (currentKey) { const value = cleanText(buffer.join('\n')); if (value) { sections[currentKey] = value; } buffer = []; } }
     const headingMap = {
       'concept title':'concept_title', 'title':'concept_title', 
       'core premise':'core_premise', 'premise':'core_premise',
       'primary function':'primary_function','function':'primary_function',
       'user experience goal':'user_experience_goal','ux goal':'user_experience_goal',
       'interaction model':'interaction_model','interaction':'interaction_model',
       'tone / voice':'tone_voice','tone voice':'tone_voice','voice':'tone_voice',
       'core modes':'core_modes','modes':'core_modes',
       'required perchance fields':'required_perchance_fields','perchance fields':'required_perchance_fields',
       'suggested reminder logic':'suggested_reminder_logic','reminder logic':'suggested_reminder_logic',
       'suggested general writing instructions':'suggested_general_writing_instructions','general writing instructions':'suggested_general_writing_instructions','writing instructions':'suggested_general_writing_instructions',
       'initial message direction':'initial_message_direction','initial message':'initial_message_direction',
       'shortcut set':'shortcut_set','shortcuts':'shortcut_set',
       'lorebook hooks':'lorebook_hooks',
       'image prompt hooks':'image_prompt_hooks','image hooks':'image_prompt_hooks',
       'custom code opportunities':'custom_code_opportunities','code hooks':'custom_code_opportunities',
       'optional modules':'optional_modules',
       'unknown expansion notes':'unknown_expansion_notes','unknown handoff':'unknown_expansion_notes'
     };
     for (const line of lines) {
        const m1 = line.match(/^\s*(?:\*\*|##?|[-*]\s)?\s*([A-Za-z0-9][A-Za-z0-9 /_-]{2,80})\s*[:：]?\s*$/);
        if (m1) {
            const h = m1[1].toLowerCase().replace(/[–—-]/g,' ').replace(/[^a-z0-9/ ]/g,'').trim();
            const key = headingMap[h];
            if (key) { flush(); currentKey = key; continue; }
        }
        buffer.push(line);
     }
     flush();
     return sections;
  }
  function guessBotType(text) {
    const s = cleanText(text).toLowerCase();
    const checks = [
      ['game master', /\b(game master|gm|referee|dungeon|encounter)\b/],
      ['interactive fiction engine', /\b(interactive fiction|if engine|choice engine)\b/],
      ['worldbuilding engine', /\b(worldbuild|setting engine|lore generator)\b/],
      ['codex keeper', /\b(codex|archive|keeper|encyclopedia)\b/],
      ['research persona', /\b(research|analyst|investigator)\b/],
      ['artist assistant', /\b(artist|image|visual|design assistant)\b/],
      ['character creator', /\b(character creator|oc builder|persona forge)\b/],
      ['narrator', /\b(narrator|storyteller|scene)\b/],
      ['simulator', /\b(simulator|simulation|model)\b/],
      ['hybrid system', /\b(hybrid|multi[- ]mode|multi[- ]role)\b/]
    ];
    for (const [label, re] of checks) { if (re.test(s)) return label; }
    return 'custom bot system';
  }
  function guessInteractionModel(text) {
    const s = cleanText(text).toLowerCase();
    if (/\bmode|switch|state\b/.test(s)) return 'mode-based';
    if (/\bquestion|interview|ask\b/.test(s)) return 'guided interrogation';
    if (/\bscenario|turn|round\b/.test(s)) return 'turn-based';
    if (/\btool|panel|buttons|shortcut\b/.test(s)) return 'tool-assisted';
    if (/\bworkflow|pipeline|handoff\b/.test(s)) return 'pipeline-oriented';
    return 'conversational scaffold';
  }
  function buildUnknownHandoffPrompt(store) {
    const sec = store.latestSections || {};
    const keys = ['concept_title','core_premise','primary_function','interaction_model','core_modes','required_perchance_fields','suggested_reminder_logic','suggested_general_writing_instructions','shortcut_set','lorebook_hooks','image_prompt_hooks','custom_code_opportunities','optional_modules','unknown_expansion_notes'];
    let out = [];
    out.push('Transform the following Perchance bot skeleton into an Unknown-compatible expansion pass.');
    out.push('Preserve modularity. Do not overwrite flexible areas unless necessary. Keep confirmed design separate from optional extensions. Retain implementation hooks and leave room for custom code.');
    for (const k of keys) {
       if (sec[k]) {
         const pretty = k.replace(/_/g,' ').replace(/\b\w/g, m => m.toUpperCase());
         out.push('\n' + pretty + ':\n' + sec[k]);
       }
    }
    return out.join('\n');
  }
  function generateSummary(store) {
    const sec = store.latestSections || {};
    const parts = [];
    if (store.latestUserConcept) parts.push('Concept: ' + store.latestUserConcept.slice(0,200));
    if (sec.concept_title) parts.push('Title: ' + sec.concept_title);
    if (sec.primary_function) parts.push('Function: ' + sec.primary_function);
    if (sec.interaction_model) parts.push('Interaction: ' + sec.interaction_model);
    if (store.flags.hasSkeleton) {
      const missing = ['concept_title','core_premise','primary_function','user_experience_goal','interaction_model','tone_voice','core_modes','required_perchance_fields','suggested_reminder_logic','suggested_general_writing_instructions','initial_message_direction','shortcut_set'].filter(k => !sec[k]);
      if (missing.length) parts.push('Missing: ' + missing.join(', '));
      else parts.push('All key sections drafted.');
      if (store.flags.readyForHandoff) parts.push('Ready for Unknown handoff.');
    } else {
      parts.push('No skeleton drafted yet.');
    }
    return parts.join(' | ');
  }
  function updateFlags(store) {
    const sec = store.latestSections || {};
    store.flags.hasSkeleton = Object.keys(sec).length > 0;
    store.flags.readyForHandoff = ['concept_title','core_premise','primary_function','interaction_model','required_perchance_fields','suggested_reminder_logic','suggested_general_writing_instructions','initial_message_direction','shortcut_set'].every(k => !!sec[k]);
  }
  function storeUserConcept(content) {
    const store = getThreadStore();
    if (!store) return;
    const cleaned = cleanText(content);
    store.latestUserConcept = cleaned;
    const snapshot = { at: Date.now(), raw: cleaned, botTypeGuess: guessBotType(cleaned), interactionModelGuess: guessInteractionModel(cleaned) };
    store.conceptHistory.push(snapshot);
    store.latestBotTypeGuess = snapshot.botTypeGuess;
    store.latestModeGuess = snapshot.interactionModelGuess;
    if (store.conceptHistory.length > 25) store.conceptHistory = store.conceptHistory.slice(-25);
    store.updatedAt = Date.now();
    // generate summary
    const summary = generateSummary(store);
    store.summaryHistory.push({ at: Date.now(), summary });
    if (store.summaryHistory.length > 25) store.summaryHistory = store.summaryHistory.slice(-25);
    updateButtonVisibility();
  }
  function storeAISkeleton(content) {
    const store = getThreadStore();
    if (!store) return;
    const raw = cleanText(String(content));
    store.latestRaw = raw;
    const sections = parseSections(raw);
    store.latestSections = sections;
    updateFlags(store);
    store.latestUnknownHandoffPrompt = buildUnknownHandoffPrompt(store);
    // push version history
    store.versionHistory.push({ version: store.versionHistory.length + 1, at: Date.now(), sections: sections, raw: raw, unknownPrompt: store.latestUnknownHandoffPrompt });
    if (store.versionHistory.length > 25) store.versionHistory = store.versionHistory.slice(-25);
    // generate summary
    const summary = generateSummary(store);
    store.summaryHistory.push({ at: Date.now(), summary });
    if (store.summaryHistory.length > 50) store.summaryHistory = store.summaryHistory.slice(-50);
    store.updatedAt = Date.now();
    updateButtonVisibility();
  }
  function onMessageAdded(msg) {
    try {
      if (!msg || typeof msg !== 'object') return;
      const content = msg.content;
      if (!content) return;
      if (msg.author === 'user') {
        storeUserConcept(content);
      } else if (msg.author === 'ai') {
        storeAISkeleton(content);
      }
    } catch (err) {
      log('onMessageAdded error', err);
    }
  }
  function updateButtonVisibility() {
    try {
      const char = getCharacter();
      const store = getThreadStore();
      if (!char || !Array.isArray(char.shortcutButtons) || !store) return;
      for (const button of char.shortcutButtons) {
        const label = String(button.name || '');
        if (/New Skeleton/i.test(label)) {
          button.showIf = () => !store.flags.hasSkeleton;
        } else if (/Refine Skeleton/i.test(label) || /Tighten Skeleton/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else if (/Core Architecture/i.test(label)) {
          button.showIf = () => !!store.latestUserConcept;
        } else if (/Optional Modules/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else if (/Perchance Fields/i.test(label)) {
          button.showIf = () => !!store.latestUserConcept;
        } else if (/Reminder Logic/i.test(label) || /Writing Instructions/i.test(label) || /Initial Message/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else if (/Shortcuts/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else if (/Lorebook Hooks/i.test(label) || /Image Hooks/i.test(label) || /Code Hooks/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else if (/Unknown Handoff/i.test(label)) {
          button.showIf = () => store.flags.readyForHandoff;
        } else if (/Export Fields/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else if (/Diagnose Build/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else if (/Versions/i.test(label)) {
          button.showIf = () => store.versionHistory.length > 0;
        } else if (/Summary/i.test(label)) {
          button.showIf = () => store.summaryHistory.length > 0;
        } else if (/Reset State/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton || store.latestUserConcept;
        } else if (/Continue Build/i.test(label)) {
          button.showIf = () => store.flags.hasSkeleton;
        } else {
          button.showIf = () => true;
        }
      }
    } catch (err) {
      log('updateButtonVisibility error', err);
    }
  }
  function attachAPI() {
    globalThis.blueprintWarden ||= {};
    globalThis.blueprintWarden.getState = function() {
      const store = getThreadStore();
      return JSON.parse(JSON.stringify(store || {}));
    };
    globalThis.blueprintWarden.getVersionHistory = function() {
      const store = getThreadStore();
      return store ? JSON.parse(JSON.stringify(store.versionHistory || [])) : [];
    };
    globalThis.blueprintWarden.getSummaryHistory = function() {
      const store = getThreadStore();
      return store ? JSON.parse(JSON.stringify(store.summaryHistory || [])) : [];
    };
    globalThis.blueprintWarden.getLatestSummary = function() {
      const store = getThreadStore();
      const last = store && store.summaryHistory ? store.summaryHistory[store.summaryHistory.length - 1] : null;
      return last ? last.summary : '';
    };
    globalThis.blueprintWarden.exportFullFieldPack = function() {
      const store = getThreadStore();
      if (!store) return '';
      const sec = store.latestSections || {};
      const fields = [];
      fields.push({name:'roleInstruction',value:sec.role_instruction||''});
      fields.push({name:'reminderMessage',value:sec.suggested_reminder_logic||''});
      fields.push({name:'generalWritingInstructions',value:sec.suggested_general_writing_instructions||''});
      fields.push({name:'initialMessages',value:sec.initial_message_direction||''});
      fields.push({name:'shortcutButtons',value:sec.shortcut_set||''});
      return fields;
    };
    globalThis.blueprintWarden.exportMinimalFieldPack = function() {
      const store = getThreadStore();
      if (!store) return '';
      const sec = store.latestSections || {};
      const fields = [];
      ['core_premise','primary_function','user_experience_goal','interaction_model','tone_voice','core_modes'].forEach(k => {
        if (sec[k]) fields.push({name:k,value:sec[k]});
      });
      return fields;
    };
    globalThis.blueprintWarden.diagnose = function() {
      const store = getThreadStore();
      if (!store) return 'No state.';
      const issues = [];
      if (!store.flags.hasSkeleton) issues.push('No skeleton exists.');
      const sec = store.latestSections || {};
      ['concept_title','core_premise','primary_function','user_experience_goal','interaction_model','tone_voice','core_modes','required_perchance_fields','suggested_reminder_logic','suggested_general_writing_instructions','initial_message_direction','shortcut_set'].forEach(k => {
        if (!sec[k]) issues.push('Missing ' + k.replace(/_/g,' '));
      });
      if (!store.flags.readyForHandoff && store.flags.hasSkeleton) issues.push('Not ready for Unknown handoff (incomplete sections).');
      return issues.length ? issues.join('\n') : 'No issues detected.';
    };
    globalThis.blueprintWarden.reset = function() {
      const thread = getThread();
      if (!thread) return false;
      if (thread.customData) delete thread.customData[NS];
      getThreadStore();
      updateButtonVisibility();
      return true;
    };
  }
  function init() {
    getThreadStore();
    attachAPI();
    updateButtonVisibility();
    const thread = getThread();
    if (thread && Array.isArray(thread.messages)) {
      for (const m of thread.messages) {
        onMessageAdded(m);
      }
    }
    if (thread && typeof thread.on === 'function') {
      thread.on('MessageAdded', onMessageAdded);
    }
    log('BlueprintWarden v2 initialized.');
  }
  init();
})();
